#!/bin/bash
# HERCOSSNUX NPU - envoltorio VHDL-93 para el block design.
#
# PROBLEMA: Vivado rechaza VHDL-2008 como fichero top de un module reference
#   ERROR [filemgmt 56-195] ... of type VHDL 2008. This type is not allowed
#   as the top file in the reference.
#
# SOLUCION: npu_axi_wrap.vhd, envoltorio VHDL-93 puro que instancia
# npu_axi_top (que sigue siendo VHDL-2008). Ademas declara los atributos
# X_INTERFACE_INFO en la ENTIDAD (no en la arquitectura, GHDL lo rechaza)
# para que Vivado agrupe las senales en las interfaces AXI4 M_AXI y S_AXI
# en lugar de dejarlas como 56 pines sueltos.
#
# VERIFICADO: el testbench de integracion a traves del envoltorio da la
# misma firma que sin el (4 imagenes, SIG_CLASE=0x5C4F1068).
#
# IMPORTANTE al anadirlo al proyecto de Vivado: este fichero debe quedar
# como VHDL (93), NO como VHDL 2008. Los demas siguen en 2008.
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/rtl/npu_axi_top.vhd" ]; then
  echo "FALLO: falta rtl/npu_axi_top.vhd (corre primero el Paso 14)"; exit 1
fi
base64 -d << "EOF" > "$DIR/rtl/npu_axi_wrap.vhd"

EOF
echo "npu_axi_wrap.vhd instalado en $DIR/rtl/"
echo ""
echo "Al anadirlo en Vivado:"
echo "  set_property FILE_TYPE {VHDL} [get_files npu_axi_wrap.vhd]"
echo "  (los demas ficheros siguen como VHDL 2008)"
)
